class ConfigError(Exception):
    """Raised when configuration is invalid."""

def load_port(raw):
    try:
        return int(raw)
    except ValueError as err:
        # wrap the low-level error with a domain-specific one,
        # keeping the original cause in the traceback
        raise ConfigError(f"invalid port: {raw!r}") from err

try:
    load_port("abc")
except ConfigError as e:
    print(e)              # invalid port: 'abc'
    print(e.__cause__)    # invalid literal for int() with base 10: 'abc'

