def to_float(text):
    try:
        return float(text)
    except ValueError:
        return None   # caller can detect the failure

print(to_float("3.14"))  # 3.14
print(to_float("oops"))  # None

def divide(a, b):
    try:
        result = a / b           # may raise ZeroDivisionError
    except ZeroDivisionError:
        print("cannot divide by zero")
        return None
    else:
        print("division succeeded")
        return result
    finally:
        print("-- divide() finished --")

divide(10, 2)
divide(10, 0)

class TemperatureError(Exception):
    pass

def parse_celsius(raw):
    try:
        value = float(raw)
    except ValueError as err:
        raise TemperatureError(f"not a temperature: {raw!r}") from err
    if value < -273.15:
        raise TemperatureError(f"{value} is below absolute zero")
    return value

try:
    parse_celsius("hot")
except TemperatureError as e:
    print("handled:", e)
    print("caused by:", repr(e.__cause__))

def load_setting(config, key):
    try:
        return config[key]
    except KeyError as e:
        e.add_note(f"available keys: {list(config)}")
        raise   # re-raise the same exception, now with a note

load_setting({"host": "localhost"}, "port")  # KeyError + note

