import json

config = {"name": "pathwise", "version": 2, "tags": ["py", "learn"]}

# serialize to a file (indent=2 pretty-prints)
with open("config.json", "w", encoding="utf-8") as f:
    json.dump(config, f, indent=2)

# load it back, handling malformed input
try:
    with open("config.json", "r", encoding="utf-8") as f:
        loaded = json.load(f)
except json.JSONDecodeError as e:
    print("bad JSON:", e)
else:
    print(loaded["name"], loaded["version"])  # pathwise 2

