# ctx.py
class Section:
    def __init__(self, name):
        self.name = name

    def __enter__(self):
        print(f"-- enter {self.name} --")
        return self

    def __exit__(self, exc_type, exc_value, tb):
        print(f"-- exit {self.name} --")
        return False   # don't suppress exceptions

with Section("demo"):
    print("inside the block")

from contextlib import contextmanager

@contextmanager
def section(name):
    print(f"-- enter {name} --")
    try:
        yield name
    finally:
        print(f"-- exit {name} --")

with section("demo") as n:
    print(f"inside {n}")

@contextmanager
def managed_file(path):
    f = open(path, "w", encoding="utf-8")
    print("opened", path)
    try:
        yield f
    finally:
        f.close()
        print("closed", path)

try:
    with managed_file("out.txt") as f:
        f.write("partial")
        raise ValueError("boom")   # cleanup still runs
except ValueError as e:
    print("caught:", e)
